// ─── Shared UI atoms ──────────────────────────────────────────────────────

function SectionHeader({ title, sub }: { title: string; sub?: string }) {
  return (
    <div className="mb-4">
      <h2 className="text-lg font-bold text-foreground">{title}</h2>
      {sub && <p className="text-[12px] text-muted-foreground mt-0.5">{sub}</p>}
    </div>
  );
}

function StatusBadge({ status }: { status: Campaign["status"] }) {
  const map = {
    Active:    "bg-green-500/15 text-green-400",
    Scheduled: "bg-primary/15 text-primary",
    Draft:     "bg-muted text-muted-foreground",
    Completed: "bg-purple-500/15 text-purple-400",
  };
  return <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${map[status]}`}>{status}</span>;
}

function SelectPills({
  label, value, options, onChange,
}: { label: string; value: string; options: string[]; onChange: (v: string) => void }) {
  return (
    <div>
      <label className="text-[12px] font-semibold text-muted-foreground block mb-1">{label}</label>
      <div className="flex flex-wrap gap-1.5">
        {options.map(o => (
          <button key={o} onClick={() => onChange(o)}
            className={`px-3 py-1.5 rounded-full text-[11px] font-semibold border transition-all ${
              value === o
                ? "bg-primary text-white border-primary"
                : "bg-muted/40 text-muted-foreground border-border/50 hover:border-primary/30 hover:text-primary"
            }`}>
            {o}
          </button>
        ))}
      </div>
    </div>
  );
}

// ─── Result Viewer ────────────────────────────────────────────────────────

interface SaveProject { id: string; name: string; icon: string; }

function SaveToProjectModal({ content, label, onClose }: { content: string; label: string; onClose: () => void }) {
  const [projects, setProjects] = useState<SaveProject[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState<string | null>(null);
  const [saved, setSaved] = useState<string | null>(null);

  useEffect(() => {
    fetch("/api/projects", { credentials: "include" })
      .then(r => r.ok ? r.json() : { projects: [] })
      .then((d: { projects: SaveProject[] }) => { setProjects(d.projects ?? []); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const saveToProject = async (proj: SaveProject) => {
    setSaving(proj.id);
    await fetch(`/api/projects/${proj.id}/files`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ name: label, content, fileType: "Document", size: `${Math.round(content.length / 100) / 10} KB` }),
    });
    setSaving(null);
    setSaved(proj.id);
    setTimeout(() => { setSaved(null); onClose(); }, 1200);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center" style={{ background: "rgba(0,0,0,0.60)", backdropFilter: "blur(8px)" }}
      onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="w-full max-w-sm mx-4 rounded-3xl overflow-hidden" style={{ background: "#0f172a", border: "1px solid rgba(255,255,255,0.10)" }}>
        <div className="flex items-center justify-between px-5 py-4" style={{ borderBottom: "1px solid rgba(255,255,255,0.08)" }}>
          <p className="text-[15px] font-bold text-white">Save to Project</p>
          <button onClick={onClose} className="w-6 h-6 rounded-full flex items-center justify-center text-xs" style={{ background: "rgba(255,255,255,0.07)", color: "#9ca3af" }}>✕</button>
        </div>
        <div className="p-4 space-y-2 max-h-72 overflow-y-auto">
          {loading && <div className="flex items-center gap-2 text-[12px] text-muted-foreground py-4 justify-center"><div className="w-4 h-4 border-2 border-primary border-t-transparent rounded-full animate-spin" />Loading projects…</div>}
          {!loading && projects.length === 0 && <p className="text-[13px] text-center text-muted-foreground py-4">No projects yet. Create one in ProjectOS first.</p>}
          {projects.map(proj => (
            <button key={proj.id} onClick={() => saveToProject(proj)} disabled={!!saving}
              className="w-full flex items-center gap-3 p-3 rounded-2xl text-left transition-all"
              style={{ background: saved === proj.id ? "rgba(34,197,94,0.12)" : "rgba(255,255,255,0.04)", border: `1px solid ${saved === proj.id ? "rgba(34,197,94,0.30)" : "rgba(255,255,255,0.08)"}` }}>
              <span className="text-xl flex-shrink-0">{proj.icon || "📁"}</span>
              <p className="flex-1 text-[13px] font-semibold text-white truncate">{proj.name}</p>
              {saving === proj.id && <div className="w-4 h-4 border-2 border-primary border-t-transparent rounded-full animate-spin flex-shrink-0" />}
              {saved === proj.id && <span className="text-green-400 text-sm flex-shrink-0">✓</span>}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

function ResultViewer({ item, onBack, onSave }: { item: GenResult; onBack: () => void; onSave: () => void }) {
  const [copied, setCopied] = useState(false);
  const [saved,  setSaved]  = useState(false);
  const [showSaveModal, setShowSaveModal] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(item.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2200);
  };

  const handleSave = () => { onSave(); setSaved(true); setTimeout(() => setSaved(false), 1600); };

  const typeIcon: Record<string, string> = {
    social: "📲", email: "✉️", ad: "📣", blog: "📝", video: "🎬", campaign: "📋", general: "✨",
  };

  return (
    <div className="space-y-4 animate-fade-up">
      <div className="flex items-center gap-2 flex-wrap">
        <button onClick={onBack}
          className="flex items-center gap-1 text-[13px] font-medium hover:opacity-70 transition-opacity"
          style={{ color: "#818cf8" }}>
          <span className="text-[18px] font-light">‹</span> Back
        </button>
        <div className="flex-1" />
        <button onClick={handleCopy}
          className="text-[11px] font-semibold px-3 py-1.5 rounded-xl transition-all"
          style={{ background: copied ? "rgba(34,197,94,0.10)" : "rgba(255,255,255,0.07)", color: copied ? "#4ade80" : "rgba(255,255,255,0.70)", border: `1px solid ${copied ? "rgba(34,197,94,0.20)" : "rgba(255,255,255,0.10)"}` }}>
          {copied ? "✓ Copied" : "Copy"}
        </button>
        <button onClick={handleSave}
          className="text-[11px] font-semibold px-3 py-1.5 rounded-xl transition-all"
          style={{ background: saved ? "rgba(34,197,94,0.18)" : "rgba(34,197,94,0.10)", color: "#4ade80", border: "1px solid rgba(34,197,94,0.20)" }}>
          {saved ? "✓ Saved" : "Save"}
        </button>
        <button onClick={() => setShowSaveModal(true)}
          className="text-[11px] font-semibold px-3 py-1.5 rounded-xl transition-all"
          style={{ background: "rgba(99,102,241,0.15)", color: "#a5b4fc", border: "1px solid rgba(99,102,241,0.25)" }}>
          Save to Project
        </button>
      </div>

      <div className="flex items-start gap-3">
        <div className="w-10 h-10 rounded-2xl flex items-center justify-center text-xl flex-shrink-0" style={{ background: "rgba(99,102,241,0.12)", border: "1px solid rgba(99,102,241,0.20)" }}>
          {typeIcon[item.type] ?? "✨"}
        </div>
        <div>
          <p className="section-label mb-0.5">{item.type.toUpperCase()} · {item.createdAt.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}</p>
          <h3 className="text-[15px] font-bold text-foreground" style={{ letterSpacing: "-0.01em" }}>{item.label}</h3>
        </div>
      </div>

      <div className="rounded-2xl p-5 max-h-[60vh] overflow-y-auto" style={{ background: "rgba(14,18,42,0.70)", border: "1px solid rgba(255,255,255,0.08)" }}>
        <OutputFormatter content={item.content} />
      </div>

      <div className="flex items-center gap-2 text-[11px] text-muted-foreground/60 justify-center">
        <span>✓</span>
        <span>Generated by CreateAI Brain · Internal use · Not for publication</span>
      </div>

      {showSaveModal && (
        <SaveToProjectModal
          content={item.content}
          label={item.label}
          onClose={() => setShowSaveModal(false)}
        />
      )}
    </div>
  );
}

