// ─── Content Generator ────────────────────────────────────────────────────

function GenerateView({ onResult }: { onResult: (r: GenResult) => void }) {
  const [contentType, setContentType] = useState<ContentType>("Social Post");
  const [platform,    setPlatform]    = useState<Platform>("Instagram");
  const [emailType,   setEmailType]   = useState<EmailType>("Welcome");
  const [tone,        setTone]        = useState<Tone>("Professional");
  const [topic,       setTopic]       = useState("");
  const [generating,  setGenerating]  = useState(false);

  const typeIcons: Record<ContentType, string> = {
    "Social Post": "📲", "Email": "✉️", "Ad Copy": "📣", "Blog Post": "📝", "Video Script": "🎬",
  };

  const handleGenerate = () => {
    if (!topic.trim()) return;
    setGenerating(true);
    setTimeout(() => {
      let r: GenResult;
      switch (contentType) {
        case "Social Post":   r = generateSocialPost(topic, platform, tone); break;
        case "Email":         r = generateEmail(topic, emailType, tone); break;
        case "Ad Copy":       r = generateAdCopy(topic, "Facebook/Instagram"); break;
        case "Blog Post":     r = generateBlog(topic, "medium"); break;
        case "Video Script":  r = generateVideoScript(topic, "Standard (3–5 min)"); break;
        default:              r = BrainGen.generate(topic); break;
      }
      setGenerating(false);
      onResult(r);
    }, 600);
  };

  return (
    <div className="space-y-5">
      <SectionHeader title="Generate Content" sub="Pick a type, describe your topic, and get it instantly." />

      {/* Content type selector */}
      <div>
        <p className="text-[12px] font-semibold text-muted-foreground mb-2">Content Type</p>
        <div className="grid grid-cols-5 gap-1.5">
          {(["Social Post", "Email", "Ad Copy", "Blog Post", "Video Script"] as ContentType[]).map(t => (
            <button key={t} onClick={() => setContentType(t)}
              className={`flex flex-col items-center gap-1 p-2.5 rounded-xl border text-center transition-all ${
                contentType === t ? "bg-primary text-white border-primary" : "bg-muted/40 text-muted-foreground border-border/50 hover:border-primary/30"
              }`}>
              <span className="text-xl">{typeIcons[t]}</span>
              <span className="text-[9px] font-semibold leading-tight">{t}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Context-specific options */}
      {contentType === "Social Post" && (
        <SelectPills label="Platform" value={platform} onChange={(v) => setPlatform(v as Platform)}
          options={["Instagram", "LinkedIn", "Facebook", "Twitter", "TikTok", "General"]} />
      )}
      {contentType === "Email" && (
        <SelectPills label="Email Type" value={emailType} onChange={(v) => setEmailType(v as EmailType)}
          options={["Welcome", "Follow-Up", "Nurture", "Promotional"]} />
      )}

      <SelectPills label="Tone" value={tone} onChange={(v) => setTone(v as Tone)}
        options={["Professional", "Casual", "Enthusiastic", "Empathetic", "Bold"]} />

      {/* Topic input */}
      <div>
        <label className="text-[12px] font-semibold text-muted-foreground block mb-1.5">Topic / Description</label>
        <textarea value={topic} onChange={e => setTopic(e.target.value)}
          placeholder={
            contentType === "Social Post"  ? "e.g. The power of consistent morning routines for entrepreneurs" :
            contentType === "Email"        ? "e.g. Our new healthcare scheduling platform launch" :
            contentType === "Ad Copy"      ? "e.g. CreateAI Brain — the all-in-one business OS" :
            contentType === "Blog Post"    ? "e.g. How AI is transforming home health agencies" :
                                            "e.g. 5 reasons to start using AI in your business today"
          }
          className="w-full bg-background border border-border/50 rounded-xl p-3 text-[13px] text-foreground placeholder:text-muted-foreground resize-none outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/30 transition-all"
          rows={3} />
      </div>

      {/* Quick topic chips */}
      <div>
        <p className="text-[11px] text-muted-foreground mb-1.5">Quick start:</p>
        <div className="flex flex-wrap gap-1.5">
          {[
            "Healthcare innovation",
            "Recurring revenue streams",
            "AI for small business",
            "Client retention strategy",
            "Horse boarding services",
          ].map(q => (
            <button key={q} onClick={() => setTopic(q)}
              className="text-[10px] bg-primary/10 text-primary border border-primary/20 hover:bg-primary/15 px-2.5 py-1 rounded-full transition-colors font-medium">
              {q}
            </button>
          ))}
        </div>
      </div>

      <button onClick={handleGenerate} disabled={!topic.trim() || generating}
        className="w-full bg-primary text-white text-sm font-semibold py-3 rounded-xl hover:opacity-90 transition-opacity disabled:opacity-40 flex items-center justify-center gap-2">
        {generating
          ? <><div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" /><span>Generating…</span></>
          : <span>Generate {typeIcons[contentType]} {contentType}</span>
        }
      </button>

      <p className="text-[10px] text-muted-foreground text-center">All content generated by CreateAI Brain · Internal use only</p>
    </div>
  );
}

// ─── Campaign Planner ─────────────────────────────────────────────────────

function CampaignView({ campaigns, onResult }: { campaigns: Campaign[]; onResult: (r: GenResult) => void }) {
  const [planGoal,     setPlanGoal]     = useState("");
  const [planAudience, setPlanAudience] = useState("");
  const [planTimeline, setPlanTimeline] = useState("4 weeks");
  const [planning,     setPlanning]     = useState(false);
  const [tab,          setTab]          = useState<"list" | "plan">("list");

  const handlePlan = () => {
    if (!planGoal.trim()) return;
    setPlanning(true);
    setTimeout(() => {
      const r = generateCampaign(planGoal, planAudience || "your target audience", planTimeline);
      setPlanning(false);
      onResult(r);
    }, 700);
  };

  return (
    <div className="space-y-4">
      <SectionHeader title="Campaigns" sub="Manage active campaigns and generate new campaign plans." />

      <div className="flex gap-1.5">
        {(["list", "plan"] as const).map(t => (
          <button key={t} onClick={() => setTab(t)}
            className={`flex-1 py-2 rounded-xl text-[12px] font-semibold transition-all ${tab === t ? "bg-primary text-white" : "bg-muted text-muted-foreground hover:bg-muted/80"}`}>
            {t === "list" ? "📋 Campaign List" : "✨ Plan a Campaign"}
          </button>
        ))}
      </div>

      {tab === "list" && (
        <div className="space-y-2">
          {campaigns.map(c => (
            <div key={c.id} className="bg-background rounded-2xl border border-border/50 p-4 space-y-2">
              <div className="flex items-center gap-2">
                <div className="w-9 h-9 rounded-xl flex items-center justify-center text-lg flex-shrink-0" style={{ backgroundColor: c.color + "22" }}>📣</div>
                <div className="flex-1 min-w-0">
                  <p className="font-semibold text-[13px] text-foreground">{c.name}</p>
                  <p className="text-[10px] text-muted-foreground">{c.goal} · {c.audience}</p>
                </div>
                <StatusBadge status={c.status} />
              </div>
              {c.reach > 0 && (
                <div className="grid grid-cols-3 gap-2 pt-1">
                  {[
                    { label: "Reach",        value: c.reach.toLocaleString() },
                    { label: "Conversions",  value: c.conversions.toString() },
                    { label: "Revenue",      value: c.revenue },
                  ].map(s => (
                    <div key={s.label} className="bg-muted/40 rounded-lg p-2 text-center">
                      <p className="text-[12px] font-bold text-foreground">{s.value}</p>
                      <p className="text-[9px] text-muted-foreground">{s.label}</p>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      {tab === "plan" && (
        <div className="space-y-4">
          <div>
            <label className="text-[12px] font-semibold text-muted-foreground block mb-1.5">Campaign Goal</label>
            <input value={planGoal} onChange={e => setPlanGoal(e.target.value)}
              placeholder="e.g. Generate 200 leads in 4 weeks"
              className="w-full bg-background border border-border/50 rounded-xl px-3 py-2.5 text-[13px] text-foreground placeholder:text-muted-foreground outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/30 transition-all" />
          </div>
          <div>
            <label className="text-[12px] font-semibold text-muted-foreground block mb-1.5">Target Audience</label>
            <input value={planAudience} onChange={e => setPlanAudience(e.target.value)}
              placeholder="e.g. Small healthcare agencies, 10–50 employees"
              className="w-full bg-background border border-border/50 rounded-xl px-3 py-2.5 text-[13px] text-foreground placeholder:text-muted-foreground outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/30 transition-all" />
          </div>
          <SelectPills label="Timeline" value={planTimeline} onChange={setPlanTimeline}
            options={["2 weeks", "4 weeks", "6 weeks", "8 weeks", "3 months"]} />
          <button onClick={handlePlan} disabled={!planGoal.trim() || planning}
            className="w-full bg-primary text-white text-sm font-semibold py-3 rounded-xl hover:opacity-90 transition-opacity disabled:opacity-40 flex items-center justify-center gap-2">
            {planning
              ? <><div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" /><span>Planning…</span></>
              : "Generate Campaign Plan"
            }
          </button>
        </div>
      )}
    </div>
  );
}

// ─── Analytics ────────────────────────────────────────────────────────────

function AnalyticsView() {
  const stats = [
    { label: "Total Reach",        value: ANALYTICS.totalReach,       icon: "👁️",  color: "#007AFF" },
    { label: "Total Conversions",  value: ANALYTICS.totalConversions, icon: "🎯",  color: "#34C759" },
    { label: "Est. Revenue",       value: ANALYTICS.totalRevenue,     icon: "💰",  color: "#FF9500" },
    { label: "Avg Open Rate",      value: ANALYTICS.avgOpenRate,      icon: "📧",  color: "#5856D6" },
    { label: "Avg Click Rate",     value: ANALYTICS.avgClickRate,     icon: "👆",  color: "#FF2D55" },
    { label: "Top Channel",        value: ANALYTICS.topChannel,       icon: "🏆",  color: "#30B0C7" },
  ];

  const channels = [
    { name: "Email",     pct: 42, color: "#007AFF" },
    { name: "Social",    pct: 28, color: "#34C759" },
    { name: "Paid Ads",  pct: 18, color: "#FF9500" },
    { name: "Organic",   pct: 12, color: "#BF5AF2" },
  ];

  return (
    <div className="space-y-5">
      <SectionHeader title="Analytics" sub="Campaign performance overview — internal mock data." />

      <div className="grid grid-cols-2 gap-2">
        {stats.map(s => (
          <div key={s.label} className="bg-background rounded-2xl border border-border/50 p-3 flex items-center gap-2.5">
            <div className="w-9 h-9 rounded-xl flex items-center justify-center text-lg flex-shrink-0" style={{ backgroundColor: s.color + "22" }}>
              {s.icon}
            </div>
            <div className="min-w-0">
              <p className="text-[15px] font-bold text-foreground">{s.value}</p>
              <p className="text-[10px] text-muted-foreground">{s.label}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Channel breakdown */}
      <div className="bg-background rounded-2xl border border-border/50 p-4 space-y-3">
        <p className="text-[12px] font-bold text-foreground uppercase tracking-wider">Channel Breakdown</p>
        {channels.map(ch => (
          <div key={ch.name} className="space-y-1">
            <div className="flex justify-between text-[12px]">
              <span className="font-medium text-foreground">{ch.name}</span>
              <span className="text-muted-foreground">{ch.pct}%</span>
            </div>
            <div className="w-full bg-muted rounded-full h-2">
              <div className="h-2 rounded-full transition-all" style={{ width: `${ch.pct}%`, backgroundColor: ch.color }} />
            </div>
          </div>
        ))}
      </div>

      {/* Top campaign */}
      <div className="bg-primary/10 border border-primary/20 rounded-2xl p-4 space-y-1">
        <p className="text-[10px] font-bold text-primary uppercase tracking-wider">Top Performing Campaign</p>
        <p className="font-bold text-foreground">{ANALYTICS.topCampaign}</p>
        <p className="text-[12px] text-muted-foreground">9,100 reach · 540 conversions · $42,660 est. revenue</p>
      </div>

      <p className="text-[10px] text-muted-foreground text-center">All analytics are mock/internal. No real tracking. Demo-only.</p>
    </div>
  );
}

// ─── History ──────────────────────────────────────────────────────────────

function HistoryView({ history, onSelect }: { history: GenResult[]; onSelect: (r: GenResult) => void }) {
  const typeIcons: Record<string, string> = {
    social: "📲", email: "✉️", ad: "📣", blog: "📝", video: "🎬",
    campaign: "📋", general: "✨",
  };

  if (history.length === 0) {
    return (
      <div className="text-center py-16 space-y-3">
        <p className="text-4xl">📭</p>
        <p className="font-semibold text-foreground">No content generated yet</p>
        <p className="text-[12px] text-muted-foreground">Use the Generate tab to create your first piece.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <SectionHeader title="Content History" sub={`${history.length} item${history.length !== 1 ? "s" : ""} generated`} />
      <div className="space-y-2">
        {history.map(h => (
          <button key={h.id} onClick={() => onSelect(h)}
            className="w-full flex items-start gap-3 p-3.5 bg-background rounded-2xl border border-border/50 hover:border-primary/20 hover:shadow-sm transition-all text-left">
            <span className="text-xl flex-shrink-0 mt-0.5">{typeIcons[h.type] ?? "✨"}</span>
            <div className="flex-1 min-w-0">
              <p className="font-semibold text-[13px] text-foreground truncate">{h.label}</p>
              <p className="text-[10px] text-muted-foreground mt-0.5">{h.createdAt.toLocaleTimeString()}</p>
            </div>
            <span className="text-muted-foreground text-xs mt-1 flex-shrink-0">→</span>
          </button>
        ))}
      </div>
    </div>
  );
}

// ─── Main App ─────────────────────────────────────────────────────────────

export function MarketingApp() {
  const [view,      setView]      = useState<MarketingView>("home");
  const [history,   setHistory]   = useState<GenResult[]>([]);
  const [activeResult, setActiveResult] = useState<GenResult | null>(null);
  const [campaigns, setCampaigns] = useState<Campaign[]>(SEED_CAMPAIGNS);

  const NAV = [
    { id: "home",      label: "Home",     icon: "🏠" },
    { id: "generate",  label: "Create",   icon: "✨" },
    { id: "campaign",  label: "Campaigns",icon: "📣" },
    { id: "analytics", label: "Analytics",icon: "📊" },
    { id: "history",   label: "History",  icon: "📂" },
  ];

  const handleResult = (r: GenResult) => {
    setHistory(prev => [r, ...prev]);
    setActiveResult(r);
    setView("result");
  };

  return (
    <div className="flex flex-col h-full">
      {/* Top nav */}
      <div className="flex-none border-b" style={{ background: "rgba(8,10,22,0.80)", borderColor: "rgba(255,255,255,0.07)", backdropFilter: "blur(24px)" }}>
        <div className="flex overflow-x-auto px-2 py-1.5 gap-0.5 no-scrollbar">
          {NAV.map(n => (
            <button key={n.id} onClick={() => setView(n.id as MarketingView)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-[11px] font-semibold whitespace-nowrap transition-all duration-150 flex-shrink-0 ${
                view === n.id || (view === "result" && n.id === "history")
                  ? "text-white"
                  : "text-muted-foreground hover:text-foreground"
              }`}
              style={
                view === n.id || (view === "result" && n.id === "history")
                  ? { background: "linear-gradient(135deg, #6366f1 0%, #5457d8 100%)", boxShadow: "0 2px 8px rgba(99,102,241,0.35)" }
                  : {}
              }
              onMouseEnter={e => {
                if (view !== n.id) (e.currentTarget as HTMLElement).style.background = "rgba(255,255,255,0.07)";
              }}
              onMouseLeave={e => {
                if (view !== n.id) (e.currentTarget as HTMLElement).style.background = "";
              }}
            >
              <span>{n.icon}</span>
              <span>{n.label}</span>
            </button>
          ))}
          <div className="ml-auto flex items-center px-2">
            <span className="text-[10px] text-muted-foreground/60">{history.length} generated</span>
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4">
        {view === "result" && activeResult
          ? <ResultViewer item={activeResult} onBack={() => setView("history")}
              onSave={() => setHistory(prev => prev.find(h => h.id === activeResult.id) ? prev : [activeResult, ...prev])} />
          : view === "home"
          ? <HomeView setView={setView} campaigns={campaigns} history={history} />
          : view === "generate"
          ? <GenerateView onResult={handleResult} />
          : view === "campaign"
          ? <CampaignView campaigns={campaigns} onResult={handleResult} />
          : view === "analytics"
          ? <AnalyticsView />
          : view === "history"
          ? <HistoryView history={history} onSelect={r => { setActiveResult(r); setView("result"); }} />
          : null
        }
      </div>
    </div>
  );
}
